#include "interface.h"

#include <stdint.h>

static inline uint8_t blend_byte(uint8_t s, uint8_t d, uint8_t a) {
    uint32_t tmp = (uint32_t)s * a + (uint32_t)d * (255u - a) + 127u;
    return (uint8_t)(tmp / 255u);
}

uint64_t run(const uint8_t* src, const uint8_t* dst, int width, int height, int iters) {
    size_t pixels = (size_t)width * (size_t)height;
    uint64_t hash;
    for (int iter = 0; iter < iters; ++iter) {
        hash = 1469598103934665603ULL;
        const uint8_t* s = src;
        const uint8_t* d = dst;
        for (size_t i = 0; i < pixels; ++i) {
            uint8_t a = s[3];
            uint8_t r = blend_byte(s[0], d[0], a);
            uint8_t g = blend_byte(s[1], d[1], a);
            uint8_t b = blend_byte(s[2], d[2], a);
            hash ^= (uint64_t)r;
            hash *= 1099511628211ULL;
            hash ^= (uint64_t)g;
            hash *= 1099511628211ULL;
            hash ^= (uint64_t)b;
            hash *= 1099511628211ULL;
            hash ^= (uint64_t)255u;
            hash *= 1099511628211ULL;
            s += 4;
            d += 4;
        }
    }
    return hash;
}
